-- 2. Water status (1:1) -----------------------------------------------------
INSERT INTO public.water_status
  (community_id, status, coverage_percent, existing_infrastructure, proposed_solutions, remarks, action, schools_access, source_sheet)
SELECT c.id, v.status, v.coverage::numeric, v.infra, v.solutions, v.remarks, v.action, v.schools, 'GWI Hinterland Water Register'
FROM (VALUES
  (1, 'Mabaruma Central', 'partial', 100, 'This area has 1 cathment that supply water on a sectional delivery system twice a week to residents. They are the Mabaruma pump station which supplies (thomas hill, Mabrauma township, Mabaruma compound, broomes hill/turn, Kumaka and piece of the Hosororo stretch), the Barbina pump station which supplies Barbina and the Wanina which supplies the upper and lower Hosororo hill, upper and lower Wanina Hill', 'GWI is attempting to drill wells in small sections so as to transition to more hours of service to the residents', NULL, NULL, '2 Secondary Schools, 2 Primary, 2 Nursery- These schools are being supplied from the Mabaruma Pump station and receiving adequate water supply'),
  (1, 'Khanhill', 'partial', 15, 'A new well was drilled in 2026', 'GWI and the council has partnered to undertake a water expansion project to increase the access to more residents. This is expected to be completed by July 2026', 'Awaiting MPL to run electricity and the wood was order for the fence', 'Provided the community with 270 2" PVC pipes so far, awaiting electricity to activate the well, letter was sent to the cdc chair person', 'Area has 1 nursey school'),
  (1, 'Mabaruma Settlement', 'partial', 90, 'A new water water systems was constructed in 2024, this system supplies about 90% of the residents. The 10% lives at the rocks road area and utilizes a trestle, however not all the resident are benefitting from the system.', 'The rocks road to get new well  soon which will bring the system to 100% coverage', 'geophysical logging was done and drilling has commence and is 80% completed', NULL, 'This area has 1 nursey school which recieve water from the well'),
  (1, 'Hobo Hill', 'partial', 93, 'has 1 water system and some residents recieve from the Mabaruma catchment', 'Some resident received water from the mabaruma pump station on a sectional delivery basis while 90% of the village receive water from the new well', 'New well is up and running, however the water is merky. pump to waste was done to see if the water color changes', NULL, 'Students in this area attend school in Mabaruma'),
  (1, 'Wauna Scheme', 'partial', 90, 'Wauna scheme has 1 water systems', 'Well is active and needs monitoring', 'Well was educted, however well casing might have rupture, well is up and running', 'System being monitored', NULL),
  (1, 'Barabina', 'adequate', 100, 'Residents currently receive surface water using electric pump on a sectional delivery from a spring 3 times a week. .Water supply system covers about 100% of the community', 'The line was change from 4 inch to 2 in 2025, thus increasing the capability of supply', NULL, 'System being monitored', 'Students in this area attend school in Mabaruma'),
  (1, 'Barimanobo', 'adequate', 100, 'A catchment that was done by the village is utilize, A new well was attempted but fail in 2025', 'The catchment is up and running and provide water to all the residents on a sectional delivery system', 'the pool need desluging, a valvle was install to help keep the water on a hill top, this stop all complains', NULL, 'Students in this area attend school in Mabaruma'),
  (1, 'Hosororo', 'adequate', 95, 'Residents currently receive untreated surface water from a spring 3-4 times weekly. About 95% of the community is receiving supply. In dry periods the volume of water available is significantly reduced.', 'New well is completed and is being activated', 'Receive water from the wanina system', NULL, 'Students in this area attend school in Mabaruma'),
  (1, 'Tobago', 'adequate', 95, 'A new well was drilled in 2025', 'well is functional', NULL, 'maintenance and monitoring by GWI staff', 'This area has 1 primary school, receives water from Wanina catchment'),
