  (4, 'Silver Hill', 'adequate', 95, 'This community is located on the Linden/Soesdyke Highway. A new well was drilled in 2023 & 2025.', 'Continue to monitor and maintain', 'The current water system will bring access to 95%, the other 5% are residents that live a great distance from the main areas of the community. However they can still receive water at nearby standpipes.', NULL, NULL),
  (5, 'Moraikobai', 'partial', 90, 'The community is situated on the Mahaicony River. Extension were done to the system in 2021 and upgrades are currently being done to increase the level of service.', 'A new water system to be constructed in Lower Moraikobai in 2026 to provide increased access.', 'The current water system will bring access to 90%, the other 10% are residents that live in Lower Moraikobai further down the Mahaicony River. A new system to be constructed in 2026 since this is a developing area.', NULL, NULL),
  (6, 'Orealla', 'partial', 90, 'The community is located up the Corentyne River. The community has a deep well with a Surface pump powered by a solar system and generator, a new trestle was constructed in 2024.', 'A new system to be constructed in 2026 to provide 100% coverage and boost level of service in the community.', 'The current water system provides access to 90%, the other 10% are residents that live in a different section of the community. A new water system to be constructed in 2026 to provide 100% coverage.', NULL, NULL),
  (6, 'Siparuta', 'partial', 60, 'The community is located up the Corentyne River. The community has a Well with submersible pump.', 'A new system to be constructed in 2026 to provide 100% coverage and boost level of service in the community.', 'The current water system provides access to 60%, the other 40% are residents that live in a different section of the community. A new water system to be constructed in 2026 to provide 100% coverage.', NULL, NULL),
  (6, 'Baracarra', 'partial', 90, 'The community is located in a tributary of the Berbice River. Currently has no water supply system but a contract has recently be awarded to construct a new system.', '2 new water systems were constructed in 2025/2026.', '90 % of the community will have access to potable water after the completion of the project.', NULL, NULL),
  (10, 'Great Falls', 'adequate', 95, 'The community is located off the Linden/Mabura Highway near 58 Miles Community.', 'Upgrade works are currently being undertaken by Supreme Construction and is expected to be completed before the ending of 2025.', 'The current water system will bring access to 95%, the other 5% are residents that live a great distance from the main areas of the community. However they can still receive water at nearby standpipes.', NULL, NULL),
  (10, '47 Miles Mabura', 'no_system', 0, 'The community is located on the Linden/Mabura Highway.', 'A new water system to be contructed in 2026 by Coastal Department.', '100% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (10, '58 Miles Mabura', 'no_system', 0, 'The community is located on the Linden/Mabura Highway. Currently has a dilapidated system.', 'A new water system to be contructed in 2026 by Coastal Department.', '100% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (10, 'Hururu', 'partial', 60, 'The community is located in the Berbice River. The community has a Well with submersible pump.', 'A new water system to be constructed in 2026.', '100% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (10, 'Kimbia', 'partial', 60, 'The community is located in the Berbice River. A new water system was constucted in 2025 by the school area and is currently being monitored.', 'A new water system to be constructed in 2026 on the other river bank of the community.', '100% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (10, 'Malali', 'partial', 0, 'Theres an old dilapidated GWI system which cannot be repaired. Currently has no water supply system but a contract has recently be awarded to construct a new system.', 'A new water system to be contructed in 2026 by Coastal Department.', '100% of the community will have access to potable water after the completion of the project in 2025.', NULL, NULL),
  (10, 'Muritaro', 'adequate', 90, 'Theres an old dilapidated GWI system which cannot be repaired. Currently has no water supply system but a contract has recently be awarded to construct a new system.', 'A new water system is completed  in this community in 2025', '100% of the community has access to potable water', NULL, NULL),
  (10, 'Goshen - Riversview', 'adequate', 100, 'well, PV system distribution network', 'Continue to monitor and maintain', 'Continue to monitor and maintain', NULL, NULL),
  (10, 'New Spring Garden- Riversview', 'adequate', 100, 'well, PV system distribution network', 'Continue to monitor and maintain', 'Continue to monitor and maintain', NULL, NULL),
  (10, 'New Found Out- Riversview', 'adequate', 100, 'well, PV system distribution network', 'Continue to monitor and maintain', 'Continue to monitor and maintain', NULL, NULL),
  (10, 'Falmouth - Riversview', 'adequate', 100, 'well, PV system distribution network', 'Continue to monitor and maintain', 'Continue to monitor and maintain', NULL, NULL),
  (10, 'Rockstone', 'no_system', 0, 'A new water system is currently being constructed', 'A new water system to be constructed by the ending of 2025 by the Coastal Department.', '100% of the community will have access to potable water after the completion of the project in 2025.', NULL, NULL),
  (10, 'Sandhills/Hittia', 'partial', 60, 'The community is located in the Berbice River. The community has a Well with submersible pump.', 'A new water system to be constructed in 2026.', '100% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (10, 'Wikki/Calcuni', 'adequate', 95, 'The community is located in the Berbice River. A new water system was constucted in 2025 by the school area and is currently being monitored.', 'Continue to monitor and maintain', 'The current water system will bring access to 95%, the other 5% are residents that live a great distance from the main areas of the community. However they can still receive water at nearby standpipes.', NULL, NULL),
  (10, 'Wiruni', 'partial', 60, 'The community is located in the Berbice River. The community has a Well with submersible pump.', 'A new water system to be constructed in 2026.', '100% of the community will have access to potable water after the completion of the project in 2025.', NULL, NULL),
  (10, 'Fal Mouth', 'adequate', 100, 'The community is located in the Essequibo River. Two new water systems were constucted in 2024.', 'Continue to monitor and maintain', 'Continue to monitor and maintain', NULL, NULL),
  (10, 'Coomacka', 'no_system', 0, 'no current active water supply system.', 'A new water system to be constructed in 2026.', '95% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (10, 'Old England', 'no_system', 0, 'no current active water supply system.', 'A new water system to be constructed in 2026.', '100% of the community will have access to potable water after the completion of the project in 2026.', NULL, NULL),
  (9, 'Lethem', 'adequate', 98, 'Lethem’s water infrastructure comprises six fully operational pumping stations, namely: Old Culver City, New Culver City, Kanaku, Tabatinga, Bon Success, and the Industrial Site. These stations are interconnected through a comprehensive distribution network that provides an impressive 98% coverage of the main township, ensuring that the population has access to treated, chlorinated water around the clock. A seventh pumping station is currently undergoing testing to supply the newly established TrackCHPA housing scheme. This station operates independently from the main network, which continues to efficiently serve the broader population of Lethem.', NULL, 'Water quality and pump station operations are monitored on a monthly basis.  Several of the existing pump stations in Lethem are producing hard water due to the high mineral content of the aquifers currently in use. As a long-term solution, GWI intends to drill additional wells in targeted areas where geological assessments indicate the potential for softer water sources. This initiative aims to gradually improve overall water quality across the Lethem network and reduce the impacts of hardness on both the distribution system and consumers.', NULL, 'In Lethem, GWI currently provides water to three nursery schools and one primary school, all of which have adequate access to supply. However, the secondary school now under construction does not yet have access to a water system, highlighting a gap that will require attention to ensure reliable service once the facility becomes operational.'),
  (9, 'Fly Hill', 'adequate', 95, 'The community of Flyhill, with a population of 178, is served by a drilled well equipped with an 11 SQF submersible pump powered by a photovoltaic system. Water is stored in elevated metal trestle with storage tanks and distributed through a network that provides coverage to approximately 95% of households. The remaining 5% resides far and scatterd in the outskirts of the village.', NULL, 'Village coverage is 90%. The other 10% of the residents reside far from the water system. A total of 6 households reside more than 500 meters away and are scattered throughout the village.', NULL, 'Fly Hill have 1 nursery and 1 primary that are receiving adequate water supply from GWI system.'),
  (9, 'Hiowa', 'adequate', 95, 'Hiowa has three water supply systems: two serving the main cluster and one serving the western cluster. Two of the wells were recently activated, with a newly installed distribution network and an elevated storage system constructed to serve the central cluster. In the western section, a new well was drilled and activated, and a trestle was built to support storage. GWI, in collaboration with the Village Council, has recently completed the installation of a distribution network to expand service coverage in that area. Current water coverage stands at approximately 95%,', NULL, 'GWI has recently acticated a new water supply system in Hiowa village, whic is now providing potable water to the residents. COSs to continue monitoring the operation and maintenance of this pumping station.', NULL, '1 nursery, 1 primary school connected to GWI system and is receiving adequatge water supply'),
  (9, 'Kaicumbay', 'adequate', 97, 'Groundwater from 2 drilled wells, a hand-dug well, 3 PV systems, elevated Storage - The Kaicumbay water supply system has undergone significant improvements, with the recent activation of a new well by GWI and village council. The system operates at full capacity, providing residents with a consistent and adequate water supply with current Coverage 97%', NULL, 'The other 5% of the residents or 6 households residing more than 500 meters from access to water system.', NULL, '1 nursery, 1 primary school connected to GWI system and is receiving adequatge water supply'),
  (9, 'Katoka', 'adequate', 92, 'Groundwater -Hand-dug well, new drilled well, elevated storage, PV System- The village has one drilled well that provides a reliable source of groundwater. A distribution network efficiently delivers water to 90% of the population through private standpipes.', NULL, 'Proposed for a new water supply system for 25 households (sagrimanta) cluster.', NULL, '1 nursery, 1 primary and 1 secondary school- the nursery and Primary school are connected to the GWI water system and are receiving adequate supply.'),
  (9, 'Kumu', 'adequate', 90, 'Groundwater from two drilled wells, one hand-dug well, 3 PV systems, 2 elevated storages - Kumu village has 3 water systems that provides for 90% of the population, two of which are drilled wells, and one hand-dug well. All three system are connected via a distribution network providing potable water to the resident through standpipes. There are two concrete trestle that provides storage for extended services after pumping hours.', NULL, 'The other 10% of the residents reside far off and are scattered. Proposed for a new water supply system for Western section of community in 2026.', NULL, '1Nursery, 1 primary school - both schools are connected to GWI water system and are presently receiving adequate supply'),
  (9, 'Marakanata', 'adequate', 98, 'Drilled well, PV system, Distribution network, timber trestle - These residents recieves potable water from a drilled well with PV system and a storage unit that supplies water after pumping hours, through a distribution network. Current Coverage 98%', NULL, 'System fully functional and providing 98% coverage. The remaining 2% resides far and scattered', NULL, 'No School'),
  (9, 'Moco Moco', 'adequate', 95, 'Moco Moco Village, with a population of 621, is supplied by two drilled wells that together provide water coverage to about 95% of the community through a piped distribution network with household connections. The systems include two elevated trestles, one concrete and one metal, for storage. One well is powered by the grid, while the other operates on solar power.', NULL, 'It is proposed to drill an additional well in the Village under 2026 budget to improve water supply and ensure service reliability for all residents', NULL, '1 nursery, 1 primary - both schools are connected to GWI water system and are receiving adequate suopply.'),
  (9, 'Nappi', 'adequate', 95, 'Nappi Village is served by three drilled wells and one hand-dug well, each supported by photovoltaic systems. The infrastructure includes two elevated storage facilities: a main metal trestle serving the central cluster and a concrete trestle serving the southern cluster. The third well pumps directly into the distribution line without storage. A piped network provides household-level connections and covers about 95% of the community. One of the wells was recently activated to supply the main trestle, further strengthening the central distribution system', NULL, 'The other 5% of the residents reside far off and are scattered.', NULL, '1 nursery, 1 primary, and 1 secondary school - the nursery and Primary school are connected to the GWI water system and are receiving an adequate supply. The secondary school is currently under construction and will receive a dedicated water supply system to serve the school''s campus.'),
  (9, 'Parikwarunau', 'adequate', 98, 'Parikawarinau is supplied by a drilled well with elevated storage and a distribution network that currently provides coverage to about 95% of the community. In 2025, GWI expanded the distribution network increasing the coverage. The water supply system at Parikawarinau comprises of a drilled well, PV system, elevated metal storage, and a distribution network.', NULL, 'The other 2% of the residents reside far off from the water system.', NULL, '1 nursery, 1 primary - both schools are connected to GWI water system and are receiving adequate supply.'),
  (9, 'Parishara', 'adequate', 98, 'Parishara Village is supplied by three drilled wells, supported by a main concrete elevated storage that serves the central cluster. A well-developed distribution network, with household service connections, provides water coverage to approximately 98% of the community. All systems are currently functioning adequately and reliably meeting the community’s potable water needs.', NULL, 'The remaining 2% are residing far and scattered.', NULL, '1 nursery, 1 primary - both schools are connected to GWI water system and are receiving adequate supply.'),
  (9, 'Quatata', 'adequate', 98, 'Quatata Village, with a population of 258, is served by two drilled wells and a main concrete elevated trestle for storage. The systems operate with photovoltaic power and supply a distribution network with household service connections that currently cover about 98% of the community.', NULL, 'The remaining 3% are residing far and scattered. A total of 29 households living 1km away from water system, GWI to expand to capture additional households.', NULL, '1 n usrey, 1 primary - both schools are connected to GWI system and are receiving adequate water supppl.'),
  (9, 'Quarrie', 'adequate', 98, 'Quarry Village is served by two drilled wells with metal elevated storage tanks that supply two main clusters, including the school, health post, and residences. A well-developed distribution network provides water coverage to about 98% of the community. Service delivery is strong, and residents receive an adequate and reliable supply of potable water', NULL, 'The remaining 2% resides far and scattered.', NULL, '1 Nursery, 1 Primary - both schools are connected to the GWI water system and are receiving an adequate supply.'),
  (9, 'Semonie', 'adequate', 98, 'Groundwater from a drilled well, elevated storage, PV system -A new well was drilled and had callapse unexpectedly prompting an emergency response by GWI to drill a new replacement well to be completed in 2025. GWI has expanded the distribution network connecting 20 households. This extension has increased water coverage to 95% of the village and the village now recieves water 8-12 hours,the system operates at full capacity, providing residents with a consistent and adequate water supply daily.', NULL, 'The other 5% of the residents reside far off from the central.', NULL, '1 Nursery, 1 Primary - both schools are connected to the GWI water system, they are receiving adequate water supply supply.'),
  (9, 'St. Ignatius', 'adequate', 96, 'Groundwater - 3 drilled wells in community, 2 drilled wells at school, distribution network, service connections - The St. Ignatius water supply system boasts three fully operational drilled wells, efficiently distributing potable water to 95% of the village through a comprehensive network. Presently these is further improvements being done on the school that will require improved / longer water service.', NULL, 'The other 5% of the residents reside in areas that are now developing. Drilling of new well completed. Project in initiation phase, all materials are on site and works progressing.', NULL, '1 nursery, 1 primary and 1 secondary - The nursery school receives an adequate supply from GWI system. The Primary and Secondary school have their own dedicated systems providing adequate supply'),
  (9, 'Yupukari', 'adequate', 92, 'Groundwater from 2 drilled wells, elevated storage and 2 PV systems - The water supply system covers approximately 92% of the community, through a distribution network and service connections, at a household level. The level of service can be rated as good. The community receives 8 hours of service per day, including all the main facilities (Health center, Schools).', NULL, 'Proposed a new water supply system for 20 households (Moruca cluster) in 2026 budget. The remaining 15 households are scattered and reside far away.', NULL, '1 nursery, 1 primary and 1 secondary school - All schools are connected to GWI''s water supply.'),
  (9, 'Baitoon', 'adequate', 95, 'Baitoon Village is served by three drilled wells—two within the community and one at the school. Currently, only the school well and one community well are operational, providing adequate water supply for the village’s needs. The school well is connected to a metal storage tank, ensuring a reliable reserve for both educational and community use. A distribution network is in place, supplying water to both household and communal points, achieving approximately 95% coverage for the village. Additionally, there is an ongoing construction project to establish a new elevated metal trestle, which is expected to further enhance the storage and distribution capacity of the water system.', NULL, 'The remiaingin 5% resides far and scattered from the central area. New elevated incomplete.', NULL, '1 nursery, 1 primary, - Both Schools are connected to GWI water system and are receiving adequate supply.'),
  (9, 'Katoonarib', 'adequate', 95, 'Katoonarib Village is served by three main drilled well systems, each powered by a photovoltaic (PV) system, providing water to the Central Cluster and the Southern Cluster of the village. The Central Cluster utilizes a concrete elevated trestle, while the Southern Cluster has a metal elevated trestle for water storage. Together, these two wells and their associated distribution networks provide household-level water service to approximately 95% of the village.', NULL, 'A new water supply system was successfully completed, serving an additional 20 households with first time access.', NULL, '1 nursery, 1 primary - both Schools are connected to GWI water system and are receiving adequate Supply.'),
  (9, 'Katu''ur', 'adequate', 97, 'Katu''ur Village is served by a single drilled well, powered by a photovoltaic (PV) system, with an elevated metal storage facility currently under construction to strengthen the water supply infrastructure. The system provides water to a population of 162, achieving approximately 97% coverage. Almost all households have either a standpipe or a service connection on their premises, ensuring convenient access to safe and adequate water. The quality of water supplied is reported to be good, meeting the community’s needs effectively.', NULL, 'The other 3% of the residents reside far off and are scattered.', NULL, '1 Nursery, 1 Primary - both schools are connected to GWI''s water system and are receiving an adequate supply.'),
  (9, 'Meriwau', 'adequate', 95, 'Meriwau Village is served by a single drilled well system, supported by a concrete elevated storage tank. The village has a distribution network that provides household-level service to approximately 95% of the population, with service connections directly to individual homes. There remain 19 homes, located on the outskirts of the community, that are not connected due to their dispersed locations, which make pipeline installation challenging. Despite this, the existing infrastructure effectively meets the water needs of the majority of the village.', NULL, 'However, the remaining 5% of residents live in dispersed locations far from the central area.', NULL, '1 primary School (with 1 nursery class) - New commissioned primary is receiving adequate water supply from GWI''s water system.'),
  (9, 'Potarinau', 'adequate', 96, 'Potarinau Village is served by three drilled wells, two of which are currently active, while the third is part of an ongoing project. The village has a distribution network that provides household-level service to approximately 80% of the population. A concrete elevated trestle at the school serves as the primary storage facility for the main cluster. GWI is also undertaking a new project to establish a water supply system for an additional cluster of 15 homes, aimed at improving access for residents in the forested areas. Currently, a dry spell has affected the main cluster well, resulting in a shortage of water supply. GWI is actively monitoring the situation and planning interventions to restore adequate and reliable water service to the affected households.', NULL, 'Water supply improvement completed, 5 households will remain unserved and are residing more that 500m away from the water system,', NULL, '1 nursery, 1 Primary - both schools are connected to GWI water supply system and is currently receiving adequate water supply.'),
  (9, 'Quiko', 'adequate', 98, 'Groundwater from 2 Drilled wells, 2 PV systems, Elevated storage - GWI had recently upgraded the water supply system through community participation which had increased the overall coverage in Quiko village to 98%. In addition a new well was completed with PV system, elevated metal trestle, distribution network to serve a cluster of 20 households. With these upgrades it has increased coverage to 98% with water being distributed 12 hours daily to the residents.', NULL, 'The remaining 2% resides far away from the existing network. New elevated trestle incomplete', NULL, '1 primary School (with 1 nursery class) - school is connected to GWI water system and is receiving adequate supply.'),
  (9, 'Rupunau', 'adequate', 98, 'Rupunau Village is currently served by a single drilled well, equipped with a photovoltaic (PV) system and a metal elevated trestle with storage tanks, supplying water to the main cluster through a distribution network that covers approximately 96% of the population.  The remaining 4% of residents live in dispersed locations, making direct connection to the network challenging.', NULL, 'A new drilled well system was completed, providing an adequate water supply for the residents.', NULL, '1 nursery, 1 Primary - both schools are connected to GWI water system and are currently receiving adequate water supply.'),
  (9, 'Sawariwau', 'adequate', 95, 'Swaariwau Village, with a population of 608, is served by two drilled well systems—one located at the school and the other in the central cluster. Both systems are powered by solar photovoltaic (PV) systems and are functioning adequately. An elevated metal storage tank provides additional pumping capacity for use after sunset, ensuring continuous water supply. The village has a distribution network with household-level service connections that covers approximately 95% of the population. The remaining residents live in dispersed locations. For 2025, it is proposed to drill a new well to serve an additional cluster of 19 households, which is expected to increase overall water coverage to nearly 100%.', NULL, 'GWI, in collaboration with the village council, is currently undertaking an expansion project in the water sector.', NULL, '1, nursery, 1 primary - both schools are connected to GWI water system and are receiving adequate supply.'),
  (9, 'Sand Creek', 'adequate', 95, 'Sun Creek Village, with a population of 852, is served by two main drilled well systems that provide potable water to the community. The village has a distribution network that connects approximately 95% of households, ensuring household-level access to safe water. Water storage is supported by both a concrete and a metal elevated trestle, which provide additional pumping capacity, particularly during evening hours after sunset.', NULL, 'The proposed expansion of the Sand Creek distribution network has been programmed for the 2026 budget cycle. Implementation will commence upon approval of the allocated funds', NULL, '1 nursery, 1 primary and 1 secondary school - All schools are connected to GWI''s water supply and are receiving adequate water supply. The secondary school has its own independent water supply system that privides poitable water for the campus.'),
  (9, 'Shiriri', 'adequate', 90, 'Ground Water from a Hand-dug well, drilled well, 2 PV system, elevated storage. The Shiriri Village water supply system has recently been improved through a GWI initiative that installed a new distribution network. This development provided first-time access to potable water for 15 households, increasing water coverage in the community to 90%.', NULL, 'The other 15% of the residents reside far off from the central.', NULL, '1 primary schools (with a nursery calss) - the schools has its own water supply system and is also connected to the GWI water stsem with adequate supply.'),
  (9, 'Shulinab', 'adequate', 100, 'Shulinav Village is served by three main water supply systems, consisting of three drilled wells, each powered by a photovoltaic (PV) system. The village has two elevated metal trestles and a distribution network that provides household-level service connections, covering approximately 95% of the population. A recently completed project has expanded the system, bringing overall coverage to 100%. All water supply systems are functioning adequately, ensuring reliable access to potable water for all residents.', NULL, 'Routine maintenance, system monitoring, and timely servicing of all components will be essential to preserve the recently achieved 100% coverage and maintain system reliability', NULL, '1, nursery, 1 Primary, 1 secondary school under construction. - The nursery and Primary schools are both connected to GWI''s water system and are currently receiving adequate supply'),
  (9, 'Annai', 'adequate', 98, 'Annai Village, with a population of 667, is served by three drilled wells, each powered by a photovoltaic (PV) system, providing potable water for the community. One of the wells was recently completed to replace a hand-dug well that was depleted during the dry season, enhancing the reliability of the water supply. The village has two elevated storage tanks in the central area, supporting continuous service, and a distribution network that provides household-level connections, covering approximately 98% of the population. The existing infrastructure ensures adequate and reliable access to potable water for nearly all residents.', NULL, 'The water coverage is currently at 98% in Annai Central.', NULL, '1 nursery, 1 Primary, 1 secondary and 1 technical institute - the Nursery and Primary schools are located in the central Annai village are connected and receiving adequate water supply from GWI''s system. The Secondary and the Technical institute both have their own independent weater supply systems,'),
  (9, 'Apoteri', 'adequate', 90, 'Apoteri Village currently has limited water supply coverage, serving approximately 55% of the population. Prior to recent interventions, residents relied on a hand-dug well, which collapsed earlier this year, creating a major strain on access to potable water. In response, GWI has issued a contract for the drilling of a new water supply well, which is currently in the development stage. Following completion of the well, a distribution network will be installed, targeting at least 90% household-level coverage for the village. This project is expected to significantly improve the reliability and accessibility of potable water for Apoteri residents.', NULL, 'GWI recently implemented a new water supply improvement project. 60 households benefited from the new system. The remaining households are residing far and scattered.', NULL, '1 nursery, 1 primary - currently no water supply at the schools. GWI is in the process of drilling a well in the community that will serve both schools once completed'),
  (9, 'Aranaputa', 'adequate', 97, 'Aranaputa Village, with a population of 611, is served by two drilled well systems, each supported by a metal elevated trestle that provides additional storage and allows for continuous service during and after pumping hours. The existing distribution network currently covers approximately 90% of the population at the household level. GWI is implementing a third water supply system to serve the eastern cluster of 30 households. This project is nearing completion following the final development works on the well. Once completed, overall water coverage in Aranaputa is expected to increase to nearly 100%, ensuring reliable access to potable water for all residents.', NULL, 'GWI is currently implementing a water supply improvement project. 30 households will benefit from the new system, leaving 5 households unserved. These households are residing far and scattered.', NULL, '1 nursery, 1 Primary school - both schools receive water from their independent system and are also connected to GWI''s water supply system.'),
  (9, 'Crash Water', 'adequate', 95, 'Crashwater Village is served by two drilled wells, including a recently constructed well by GWI, which is currently in the final stage of activation. The existing well system has been insufficient to meet community demand, as water levels deplete significantly during extreme dry periods. To address this challenge, GWI drilled the new well, which will soon be activated, restoring reliable water supply. Once operational, the system is expected to provide household-level water access to approximately 95% of the village, ensuring adequate and consistent service for residents.', NULL, '20 households reside more than 1km away from the water supply system.', NULL, '1 nuresry, 1 primary - both schools are connected to the GWI water system and receiving an adequate water supply'),
  (9, 'Fairview', 'adequate', 90, 'Fairview Village is served by a single drilled well system, supported by an elevated metal storage trestle. The distribution network provides household-level water connections to approximately 90% of the population. This system was completed in 2025 and is currently active, functioning adequately to meet the village’s water needs.', NULL, '17 households residing more than 500m away from the water system.', NULL, '1 nursery, 1 Primary - Both schools are connected to GWI system.'),
  (9, 'Kwatamang', 'adequate', 98, 'Kawttamang Village is currently served by three drilled well systems, one in the Northern Cluster and one in the Central Cluster, both powered by solar photovoltaic (PV) systems. The village has two elevated metal trestles and a distribution network that provides household-level service to approximately 90% of the population. GWA is currently implementing a new water supply system for the Western Cluster, which currently lacks access to potable water. Upon completion of this project, a third PV-driven drilled well will be operational, and the distribution network will be expanded, bringing overall coverage in Guatemalan Village close to 100%.', NULL, 'A new drilled well was recently completed by GWI and is in the process of being activated', NULL, '1 Nursery, 1 Primary - both schools are connected to GWI water supply system and are receiving adequte water supply.'),
  (9, 'Kwaimatta', 'adequate', 100, 'Kawaimatta Village is served by a single drilled well, powered by a photovoltaic (PV) system, with an elevated concrete trestle supporting water storage. The village has a distribution network that currently provides household-level water connections to approximately 95% of residents. GWI had expanded the network to include an additional 15 households and increased the overall coverage to 100%, ensuring nearly universal access to potable water.', NULL, 'System will require regular monitoring and maintenance to maintain improved service coverage.', NULL, '1 Nursery, 1 Primary - both schools are connected to GWI water supply system and are receiving adequte water supply.'),
  (9, 'Massara', 'adequate', 98, 'Ground Water from 3 Drilled wells, 3 PV systems, elevated storage, distribution network and service connections - The Massara Village water supply system has recently been expanded with the completion of a new water system to serve Section 3 of the community, providing first-time access to potable water for 18 households. This addition brings the total number of water systems in the village to three, significantly improving water accessibility for residents. With water coverage now at 98%.', NULL, 'The remaining 2% residing far out and scattered.', NULL, '1 nursery, 1 primary and 1 scondary - all schools are connected to the GWI Network and are receiving water supply, however it is recommended that the secondary school have its own system.'),
  (9, 'Rewa', 'adequate', 99, 'Rewa Village is served by two recently completed drilled well systems. Both wells are active and providing adequate water supply to approximately 99% of the population.  The village has a metal elevated trestle, a distribution network, and household-level service connections, ensuring that residents have consistent access to potable water. Overall, Rewa Village’s water infrastructure is functioning well and meeting the community’s needs effectively.', NULL, '5 households residing more than 500m away from the water supply system.', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Rupertee', 'adequate', 98, 'Ground Water from 3 Drilled wells, 3 PV systems, 2 elevated storage, Service connections - The Rupertee Village water supply system has been significantly enhanced with the recent activation of a new well, providing the community with increased access to potable water. The village is now served by three drilled well systems, ensuring reliable and sustainable water supply for all residents. Current coverage 98%.', NULL, '5 households residing far and scattered.', NULL, '1 Nursery, 1 Primary -both schools are connected to the GWI network and are receiving adequate water supply'),
  (9, 'Surama', 'adequate', 95, 'Ground Water from Drilled well, PV system, elevated storage, service connection - The Surama Village water supply system recently underwent a significant upgrade with the completion of a water project funded by the Basic Needs Trust Fund (BNTF). This project has expanded the water supply infrastructure, achieving 90% coverage of the village.', NULL, 'The remaining 5% are residents who reside far away from the central area.', NULL, '1 Nursery, 1 Primary - both schools are connected remaining The water supply system and are receiving adequte water supply.'),
  (9, 'Toka', 'adequate', 95, 'Toko Village is served by a single drilled well, supported by a photovoltaic (PV) system, with water storage situated on an elevated location. The village has a distribution network providing household-level service connections to approximately 98% of the population.', NULL, 'Toka Village recently had its distribution network expanded by GWI. The project was successfully completed and is now providing improved service coverage to the community.', NULL, '1 Nursery, 1 Primary - both schools are connected remaining The water supply system and are receiving adequte water supply.'),
  (9, 'Wowetta', 'adequate', 98, 'Ground Water from 2 Drilled wells, 2PV system, 2 Elevated Storage, Service connections - The Wowetta Village water supply system is supported by two drilled wells, providing reliable access to potable water for the community. The current coverage 98%.', NULL, 'The remaining 9 households reside far and are scattered from the central area.', NULL, '1 Nursery, 1 Primary - both schools are connected remaining The water supply system and are receiving adequte water supply.'),
  (9, 'Yakarinta', 'adequate', 97, 'Yakaranta Village is served by a single drilled well system, supported by a metal elevated trestle and storage units. The village has a distribution network with household-level service connections, covering approximately 97% of the population. The existing infrastructure ensures reliable and adequate access to potable water for nearly all residents.', NULL, 'The other 3% of the residents reside far off from the central.', NULL, '1 Nursery, 1 Primary - both schools are connected remaining The water supply system and are receiving adequte water supply.'),
  (9, 'Curicock', 'adequate', 100, 'Curicock Village has recently benefited from the installation of a new water supply system, including a drilled well, a photovoltaic (PV) system, and a distribution network. The village also has an existing concrete trestle to support storage and supply. This newly completed project now provides household-level water access to approximately 95% of the population, marking the first time that residents of Genobear Village have had reliable access to potable water.', NULL, 'Project recently completed by GWI. All residents are benefitting from the water supply system.', NULL, 'No School'),
  (9, 'Cracrana', 'adequate', 98, 'Cracrana Village has recently benefited from the installation of a new drilled well, strategically located to serve Cracrana itself as well as neighbouring community Karasabai (Airstrip view area). The project, now completed and activated, includes a photovoltaic (PV) system, a distribution network, and household-level service connections. These upgrades have significantly improved access to potable water for the community and surrounding areas, ensuring more reliable and adequate water supply.', NULL, '5 households residing more that 500m away from the water supply system', NULL, 'No School'),
  (9, 'Jawari', 'adequate', 100, 'Jawari Village, a small satellite community of Karasabi, with a population of 50, has recently received its first water distribution system. The system includes a drilled well, a photovoltaic (PV) system, elevated concrete storage, a distribution network, and household-level service connections. The project has been successfully completed, providing 100% coverage for the community. Residents are now benefiting from potable water for the first time, ensuring reliable and safe access to water for all households.', NULL, 'A new water system was recently installed for the residents of Jawari village. This system was recently comissioned by Hon. Minister Deodat Indar.', NULL, 'No School'),
  (9, 'Karasabai', 'adequate', 98, 'Karasabai Village is served by a total of four drilled wells, one hand-dug well, photovoltaic (PV) systems, and two elevated storage trestles. Of the four drilled wells, one recently drilled well is currently being activated, while another serves the Central Karasabai area (Section 2) to meet the needs of that population. One of the activated wells is shared with the neighbouring Satellite Community, Cracrana, covering the Airstrip View area. The village has a distribution network providing household-level service connections, currently covering approximately 90% of residents. GWA is in the final stages of expanding the network to serve an additional 20 households, providing them with first-time access to potable water. Upon completion, overall water coverage in Karasabai Village is expected to increase to approximately 97%, ensuring reliable access for nearly all residents.', NULL, 'Projects nearing completion. Will see an increase in coverage from 90% to 97% after completion.', NULL, '1 Nursery, 1 Primary, 1 Secondary - The nursery and primary schools are connected to GWI network and are currently receiving adequate water supply. The Scondary is curently under construictuion and will require its own independent water supply system,'),
  (9, 'Kokshabai', 'adequate', 98, 'Kokshibai Village had recently been awarded a contract for the drilling of a new well and the establishment of a distribution network aimed at providing household-level water access to approximately 95% of the population. Unfortunately, after project completion, the drilled well collapsed, significantly disrupting the water supply system. Efforts to remobilize the contractor were initially delayed due to poor weather and road conditions. The contractor is now scheduled to return to the area to rectify the situation. Once completed, Kokshibai Village will have a fully functional water supply system, including a new drilled well, photovoltaic (PV) system, distribution network, elevated storage, and household-level service connections, restoring reliable access to potable water for nearly all residents.', NULL, 'New drilled well source completed and activated, GWI in the process of  interconnecting the new well source to the network.', NULL, '1 Primary School (with Nursery class) - the school is connected to their own water supply system.'),
  (9, 'Pai Pang', 'adequate', 95, 'Surface water from spring source (catchment ), new drilled well, - GWI recently completed the installation of a new water supply system at Pai Pang Village, which included the drilling of a new well. However, the newly drilled well collapsed shortly after its installation, leading to a disruption in the water supply. As a result, residents are currently receiving water from the existing gravity-fed system, which continues to serve the community temporarily. The current coverage 95%', NULL, 'A new drilled well is currently in the process of being activated.', NULL, '1 Primary School (with Nursery class) - schools is connected to GWI network and is receiving adequate water supply.'),
  (9, 'Rukumuta', 'adequate', 95, 'Ground Water - Gravity spring, drilled well, PV system, elevated Storage - The Rukumuta Village consists of an elevated storage tank, a distribution network, and service connections that provide potable water to the residents. This new system has significantly improved water accessibility, achieving 95% coverage in the community.', NULL, '33 households residing more than 3km away and are scattered.', NULL, '1 Nursery, 1 Primary - both schools are connected remaining The water supply system and are receiving adequte water supply.'),
  (9, 'Maloca Nova', 'unknown', 0, 'Residents access water from a Gravity Spring / creek . There is no GWI water source. Coverage 0%', NULL, 'Proposed for a new water supply system for Maloca Nova (13 households) in 2026.', NULL, 'No School'),
  (9, 'Tiperu', 'adequate', 95, 'Tipuru Village is served by both a surface water source, drawn from the river, and a recently completed drilled well system activated in 2025. The drilled well is powered by a photovoltaic (PV) system and is supported by elevated storage. The village has a distribution network with household-level service connections, providing potable water access to approximately 95% of the population. This dual-source system ensures reliable and adequate water supply for the community.', NULL, 'The other 5% of the residents reside far off from the central', NULL, '1 Nursery, 1 Primary - both schools are connected remaining The water supply system and are receiving adequte water supply.'),
  (9, 'Karabaicru', 'adequate', 100, 'Drilled well with PV system, trestle - Karbaicru village recieves water from a drilled well system. The coverage is 100%', NULL, 'This satellite community has a total of 13 households that rely on a  creek source for domestic use and also on a drilled well source for consumption.', NULL, '1 Primary School (with Nursery class) - schools is connected to its own independent water system.'),
  (9, 'Tiger Pond', 'adequate', 98, 'Groundwater from 2 Drilled well, 2 PV systems, Elevated storage, service connection - Tiger Pond Village is served by three drilled wells and one hand-operated well. Prior to 2026, two of the drilled wells were operational and provided the majority of the community''s water supply. However, during the recent prolonged dry period, the production yield from both active wells declined significantly, resulting in reduced water availability and limited access for residents.
In response to the situation, Guyana Water Incorporated (GWI) intervened in March 2026 and undertook the drilling of a new well within the community. The project was successfully completed, restoring a reliable water supply to residents and improving the overall performance of the water system. As a result of this intervention, Tigapon Village currently enjoys approximately 98% water coverage, with residents receiving an adequate and consistent supply of potable water.', NULL, 'The main drilled well system in Tiger Pond has been affected by dry periods, resulting in reduced production. GWI has undertaken rehabilitation works, which have slightly improved output. Two additional systems—a hand-dug well and a second drilled well—complement the main system. Plans are in place to upgrade the second drilled well to enhance water supply for the community', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Taushida', 'adequate', 95, 'Ground Water from Spring reservoir, drilled well, elevated storage, 2 Pv system - The Toushida Village water supply system comprises of a spring system, and a recently drilled well. GWI has recently completed the installation of a distribution network with active participation from the community. The project achieved 95% coverage.', NULL, 'Ongoing maintenance and monitoring of all water systems are recommended to ensure uninterrupted water supply, particularly during dry periods', NULL, '1 Primary School (with Nursery class) - schools is connected to GWI network and is receiving adequate water supply.'),
  (9, 'Wichabai', 'adequate', 98, 'Wichibai, a satellite village of Karasabai, has recently received a new drilled well, supported by a photovoltaic (PV) system and a distribution network. The system provides household-level service connections to approximately 98% of the population. An existing concrete trestle supports water storage and continuous supply. The water system has recently been completed, and residents are now benefiting from reliable access to potable water.', NULL, 'GWI had sucessfully completed the installation of a water supply system which is currently benifitting 100% of the residents.', NULL, 'No School'),
  (9, 'Yurong Paru', 'adequate', 95, 'Ground Water (Treated) - Spring source, drilled well, PV system - GWI has recently completed the installation of a distribution network and activation of a new drilled well through community participation. This collaborative effort involved active engagement from residents, fostering a sense of ownership and sustainability. The system has significantly increased coverage to 95% coverage.', NULL, 'Continuous operation and maintenance are required to sustain service especially during the dry periods.', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Achawib', 'adequate', 97, 'Achiweb Village is currently served by two drilled wells, supported by one metal elevated trestle and one concrete trestle. The village has a distribution network providing household-level service connections, covering approximately 90% of the population. GWI is implementing a new water supply system for a separate cluster of the community, which includes drilling a new well, constructing a new trestle, and extending the distribution network to serve an additional 28 households. Upon successful completion of this project, overall water coverage is expected to increase to approximately 98%. Presently, the existing system provides adequate water supply for the majority of residents; however, some households remain located more than 4 kilometers from the central system, making connection to the existing network impractical.', NULL, 'New water supply installed at Achiweb village, serving an additional 20 households with first-time access to potable water.', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Aishalton', 'adequate', 95, 'Aishalton Village is currently served by three dedicated drilled wells supplying potable water to residents. The village has a distribution network linking all three wells, household-level service connections, and one central elevated metal trestle. GWI is in the process of implementing a new water supply system for a separate cluster in the village. The drilled well and PV system for this project have been completed, and the distribution network is being installed jointly by GWI and the Village Council, currently 50% complete. Upon full completion, the project is expected to increase overall water coverage from 85% to 95%, providing enhanced access and reliability for residents.', NULL, 'New water system installed at Aishalton village to serve an additional cluster of 30 households with first-time access to potable water.', NULL, '1 Nursery, 1 Primary, and 1 Secondary School - the primary and Nursery schools are connected to GWI network and is currently receiving adequate water supply, the secondary school has its own water supply system.'),
  (9, 'Awarewaunau', 'adequate', 95, 'Awarewarnau Village is served by three drilled wells: one at the school, one in the central cluster, and one in the southern cluster. These wells, powered by solar photovoltaic (PV) systems, supply potable water to the community through a distribution network that covers approximately 95% of households. The remaining 5% of residents live in dispersed locations far from the water sources, making connection to the network impractical. To enhance service reliability, GWI has recently awarded a contract for the construction of an elevated storage facility, which will improve water availability during non-pumping hours.', NULL, '26 households are residing more than 2km away from the main water supply system and are scattered.', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Bashaizon', 'adequate', 98, 'Bashaizon Village is served by a single drilled well system, powered by a photovoltaic (PV) system, and supported by a concrete elevated trestle. The village has a distribution network with household-level service connections, providing water access to approximately 98% of the community. The existing infrastructure ensures reliable and adequate potable water supply for nearly all residents.', NULL, '4 households residing more than 1km away from the central.', NULL, '1 Primary School (with Nursery class) - schools is connected to GWI network and is receiving adequate water supply.'),
  (9, 'Chirkidnau', 'adequate', 98, 'Chirkidnau Village is served by a single drilled well, powered by a photovoltaic (PV) system, with a recently constructed and activated elevated storage facility. The village has a distribution network providing household-level service connections, covering approximately 98% of the population. The system is fully functional, ensuring reliable and adequate access to potable water for nearly all residents.', NULL, 'The project was recently completed, and the system is working and providing an adequate water supply', NULL, '1 Primary School (with Nursery class) - schools is connected to GWI network and is receiving adequate water supply.'),
  (9, 'Karaudarnau', 'adequate', 95, 'Kardaranau Village is served by three drilled wells, one of which has recently been completed and is currently being activated. The village has a distribution network that currently covers approximately 90% of households, supported by an elevated metal trestle and a concrete trestle, and PV-powered systems. GWI is implementing a project to activate the new well and expand the distribution network to serve additional sections of the community, including household-level service connections. Upon completion, overall water coverage in Krodor Village is expected to increase to approximately 95%, ensuring improved access to potable water for all residents.', NULL, 'A new water supply system was installed at Kardaranau village, which now services a total of 20 households wit first time access to potable water.', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Masakenari', 'adequate', 95, 'Hand-dug well, PV system, Elevated storage - The water supply system is fully operational and providing adequate supply for the residents of Masakanari village. The current coverage 95%.', NULL, 'Community currently constructing Hand Dug Well', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.'),
  (9, 'Maruranau', 'partial', 85, 'Maruranau Village is served by three drilled wells, supported by a photovoltaic (PV) system, with a distribution network and household-level service connections covering approximately 85% of the population. However, there are two large clusters, consisting of 26, and 27 households, that are not directly connected to the existing water supply system. To improve service reliability and coverage, a contract has been awarded for the construction of a metal elevated trestle in Maruranau Village, which will increase storage capacity and support future network expansion to these unserved clusters.', NULL, 'Proposed 2 new water supply system for 58 households (2 clusters). 10 households will remain unserved', NULL, '1 nursery, 1 Primary and 1 secondary School - both the Nursery and Primary schools are connected to GWI network and are receiving adequate water supply. The secondary school is currently under construction and will have its own independent water supply system.'),
  (9, 'Para Bara', 'no_system', 100, 'Parabara Village has experienced ongoing challenges with its water supply system despite efforts to develop new groundwater sources. Two wells were drilled to serve the community; however, the first well failed shortly after being commissioned and was unable to provide a sustainable water supply. A second well was subsequently drilled and placed into operation, but after a period of service, it began exhibiting similar performance issues to the first well, resulting in a significant reduction in production capacity. To ensure residents continue to have access to potable water, a borehole source is currently being utilized. While this source provides drinking water to the community, its production capacity is insufficient to meet the total water demand of the entire village.', NULL, 'The remaining 2% resides far and scattered', NULL, '1 Nursery, 1 Primary - connected to GWI network, however, presently there is no supply due to a callapse well. GWI is working to restore'),
  (9, 'Shea', 'adequate', 95, 'Shea Village is served by a single water supply system, which currently provides approximately 95% water coverage to the community. The existing water source is functioning satisfactorily and is adequately meeting the water demands of the households connected to the system.', NULL, '27 households are residing more thank 2km away from the water supply system. Proposed for a new water supply system.', NULL, '1 nursery, 1 primary - both schools are connected to the GWI network and are receiving adequate water supply.')
) AS v(region, name, status, coverage, infra, solutions, remarks, action, schools)
JOIN public.communities c ON c.region = v.region AND lower(c.name) = lower(v.name)
ON CONFLICT (community_id) DO UPDATE SET
  status                  = EXCLUDED.status,
  coverage_percent        = EXCLUDED.coverage_percent,
  existing_infrastructure = EXCLUDED.existing_infrastructure,
  proposed_solutions      = EXCLUDED.proposed_solutions,
  remarks                 = EXCLUDED.remarks,
  action                  = EXCLUDED.action,
  schools_access          = EXCLUDED.schools_access,
  source_sheet            = EXCLUDED.source_sheet,
  updated_at              = now();

-- 3. Baseline status log (one row per imported community; guarded) ----------
INSERT INTO public.water_status_log (community_id, previous_status, new_status, reason)
SELECT ws.community_id, NULL, ws.status, 'Initial import from GWI register'
FROM public.water_status ws
JOIN public.communities c ON c.id = ws.community_id
WHERE c.source_sheet = 'GWI Hinterland Water Register'
  AND NOT EXISTS (
    SELECT 1 FROM public.water_status_log l
    WHERE l.community_id = ws.community_id AND l.reason = 'Initial import from GWI register'
  );

